  ('customs-f19eb2bd-moex-00601', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-f9fb6a06', 'sub-customs-f19eb2bd-04', NULL, 'single_choice', 'Whatcanbeconcludedfromthisarticle?', '["Thesedifferentparentingstylesaretoogoodtobetrue", "Itisnevertoolatetolearnhowtoeducateyourchildren", "TheFrenchparentingstyleisnobetterthana“TigerMom”style", "Agoodparentingstyleshouldmakebothparentsandchildrenhappy"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "d9a57e76599e", "answer_pdf_sha1": "537eae6be0a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "英文", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00001', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-13504c0c', 'sub-diplomatic-0248a032-01', NULL, 'single_choice', '下列情境語句，何者用法最為恰當？', '["新居落成：「屋上建瓴，恭喜新居落成。」", "活動開幕：「感謝各位的蒞臨，讓這次的展覽可以厚往薄來。」", "榮退餐會：「恭喜您可以自在逍遙，從今以後可以快意恩仇了。」", "婚禮祝賀：「在這兩家合婚的大好日子，要祝福新人喜結良緣、花好月圓。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00002', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-13504c0c', 'sub-diplomatic-0248a032-01', NULL, 'single_choice', '「不要忘記生命才是創作中最重要的一環。在我們對戲劇理論抱持激情的時候，記 得要先對生命抱持激情。對生命敏感，對人好奇，對現行的世界保有批判的態度， 同時擁有廣納包容的胸襟。」 下列敘述，何者最貼近本文意旨？', '["人要正向思考，不能輕言放棄生命", "好的編劇不僅熟知理論，也對生活周遭充滿關注與熱情", "為人當有雅量，不該對別人好奇，凡事包容體諒即是尊重", "教師教導戲劇理論時不能僅照本宣科，也應教學生認真生活"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00003', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-13504c0c', 'sub-diplomatic-0248a032-01', NULL, 'single_choice', '「歷史從來都有些勢利眼。歷史的一切總要透過『層積堆疊』，經過『集體記憶』的 萃取純化，方才得以逐漸定型。然而，在此『歷史造山運動』過程之中，歷史的光 圈很容易只集中在『歷史時刻』，相對地，『時刻之前』的脈絡面貌，卻常常會被有 意無意地遺忘或改變了。」 最適合用來說明上文的是：', '["人類歷史經過漫長時間累積，是給後世的智慧結晶", "過往的歷史充滿許多偏見，編修史書尤須格外謹慎", "閱讀歷史如果僅集中特定時刻，容易忽略前後脈絡", "歷史是屬於不同族群的集體記憶，應注意地方差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00004', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-13504c0c', 'sub-diplomatic-0248a032-01', NULL, 'single_choice', '「別忘了這是個國際化的時代。到哪裡都看得到同樣的連鎖速食店、同樣的二十四 小時便利商店、同樣的好萊塢電影海報。完全陌生的角落正逐漸從這個世界上消失。 在這樣的時代我們怎麼可能還有完全的流浪？像馬可波羅、哥倫布那樣，踏上一塊 完全沒有線索可循的土地，連送信回家的信差都沒有，在我們這個時代已經越來越 像則神話。在這個所有角落越來越像的世界裡，怎麼可能還有完全的流浪？」 下列說明，最切近上文主旨的是：', '["人們渴望流浪的感覺", "最好的旅行是如同探險家一般地發現新世界", "世界趨向高度同質化，因此人們認識在地就等於認識了全世界", "全球化之下，各地過多的文化複製空間所帶來的熟悉感，將影響人們的旅行經驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00005', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-13504c0c', 'sub-diplomatic-0248a032-01', NULL, 'single_choice', '「攝影者開始發現自然界的詩意後便停不下來，畢竟捕捉動物一瞬間運動狀態的不 只是機械，還是心靈。美的喚醒如此獨特，以至於同樣一台機械交給不同的人將獲 致不同的結果，而同樣一張照片帶給觀看者的情緒震動，也絕對不是那些一開始希 望相機為科學理性服務的人所能理解的。」 下列選項，何者最不符合上文旨意？', '["相機產生有意義的畫面，是因攝影者使用的機械不同", "照片凝止自然界的運動，使觀看者更能體會自然之美", "照片讓觀看者情緒震動，因相機能捕捉動物瞬間樣態", "影像在藝術與科學間飛翔，透過心靈喚醒自然界之美"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL)
